import 'dart:convert';
import 'dart:typed_data';
import 'package:flutter/material.dart';

class PerfilInterfaz extends StatelessWidget {
  Uint8List pantalla_falsa() { String PANTALLA_FALSA = ""; return base64.decode((PANTALLA_FALSA).split(',').last); }

  double porcentaje_imagen = 1.07;
  double porcentaje_subir = 0.1;

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: Colors.white,
      body: Center(
        child: Padding(
          padding: EdgeInsets.only(
            bottom: MediaQuery.of(context).size.height * porcentaje_subir, // Ajuste dinámico
          ),
          child: SizedBox(
            width: MediaQuery.of(context).size.width * porcentaje_imagen,
            height: MediaQuery.of(context).size.height * porcentaje_imagen,
            child: Image.memory(
              pantalla_falsa(),
              fit: BoxFit.contain,
            ),
          ),
        ),
      ),
    );
  }
}

void main() {
  runApp(MaterialApp(
    home: PerfilInterfaz(),
  ));
}